package installer.org.apache.syncope.installer.containers.jboss;

public class JBoss extends AbstractContainer { private final String addContentUrl = "http://%s:%s/management/add-content" ; private final String enableUrl = "http://%s:%s/management/" ; private final boolean jbossSsl ; private final String jbossHost ; private final String jbossManagementPort ; private final String installPath ; private final String artifactId ; private final HttpUtils httpUtils ; public JBoss ( final boolean jbossSsl , final String jbossHost , final String jbossManagementPort , final String jbossAdminUsername , final String jbossAdminPassword , final String installPath , final String artifactId , final AbstractUIProcessHandler handler ) { this . jbossSsl = jbossSsl ; this . jbossHost = jbossHost ; this . jbossManagementPort = jbossManagementPort ; this . installPath = installPath ; this . artifactId = artifactId ; this . httpUtils = new HttpUtils ( jbossSsl , jbossHost , jbossManagementPort , jbossAdminUsername , jbossAdminPassword , handler ) ; } public boolean deployCore ( ) { return deploy ( UNIX_CORE_RELATIVE_PATH , "syncope.war" ) ; } public boolean deployConsole ( ) { return deploy ( UNIX_CONSOLE_RELATIVE_PATH , "syncope-console.war" ) ; } public boolean deployEnduser ( ) { return deploy ( UNIX_ENDUSER_RELATIVE_PATH , "syncope-console.war" ) ; } public boolean deploy ( final String whatDeploy , final String warName ) { final String responseBodyAsString = httpUtils . postWithDigestAuth ( String . format ( addContentUrl , jbossHost , jbossManagementPort ) , String . format ( whatDeploy , installPath , artifactId ) ) ; final JBossAddResponse jBossAddResponse = JsonUtils . jBossAddResponse ( responseBodyAsString ) ; final JBossDeployRequestContent jBossDeployRequestContent = new JBossDeployRequestContent ( jBossAddResponse . getResult ( ) . getBytesValue ( ) , warName ) ; int status = httpUtils . postWithStringEntity ( String . format ( enableUrl , jbossHost , jbossManagementPort ) , JsonUtils . jBossDeployRequestContent ( jBossDeployRequestContent ) ) ; return status == 200 ; } }